-- [ ObfusPro+ ]
local GypTk = bit32 or bit or error("ObfusPro+: Environment error");
local function ZROOkn(Nszff)
    local cRxNmzwN = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local YdCpK = string.gsub(Nszff, '[^' .. cRxNmzwN .. ']', '')
    local zRewfnV = {}
    for paYd = 1, #YdCpK, 4 do
        local ynA, Tof, sIb, rHK = string.byte(YdCpK, paYd, paYd + 3)
        if not ynA then break end
        local KAxm = string.find(cRxNmzwN, string.char(ynA)) - 1
        local IwbE = string.find(cRxNmzwN, string.char(Tof)) - 1
        local UVME = sIb and string.find(cRxNmzwN, string.char(sIb)) - 1 or 0
        local AYnq = rHK and string.find(cRxNmzwN, string.char(rHK)) - 1 or 0
        local ozay = KAxm * 262144 + IwbE * 4096 + UVME * 64 + AYnq
        local qyvt = GypTk.band(GypTk.rshift(ozay, 16), 255)
        table.insert(zRewfnV, string.char(GypTk.bxor(qyvt, 165)))
        if sIb and string.char(sIb) ~= '=' then
            qyvt = GypTk.band(GypTk.rshift(ozay, 8), 255)
            table.insert(zRewfnV, string.char(GypTk.bxor(qyvt, 165)))
        end
        if rHK and string.char(rHK) ~= '=' then
            qyvt = GypTk.band(ozay, 255)
            table.insert(zRewfnV, string.char(GypTk.bxor(qyvt, 165)))
        end
    end
    return table.concat(zRewfnV)
end
local EKIzfj = math.sin(208);
local peUJDGjJ = [===[]===]
local shGQOCv = ZROOkn(peUJDGjJ)
local tMnFoW = math.sin(441);
task.spawn(assert(loadstring(shGQOCv)))
